test_that("build_nimble_bundle validates key inputs", {

  set.seed(1)
  y <- abs(stats::rnorm(10)) + 0.1
  X_bad <- data.frame(x1 = stats::rnorm(9), x2 = stats::runif(9))

  expect_error(
    build_nimble_bundle(
      y = y,
      X = X_bad,
      backend = "sb",
      kernel = "gamma",
      GPD = FALSE,
      components = 4
    ),
    "same number of rows"
  )

  expect_error(
    build_nimble_bundle(
      y = y,
      backend = "bad",
      kernel = "gamma",
      GPD = FALSE,
      components = 4
    ),
    "one of"
  )

  expect_error(
    build_nimble_bundle(
      y = y,
      backend = "sb",
      kernel = "bad",
      GPD = FALSE,
      components = 4
    ),
    "one of"
  )

  expect_error(
    build_nimble_bundle(
      y = y,
      backend = "sb",
      kernel = "gamma",
      GPD = FALSE,
      components = 1
    ),
    "components must be an integer >= 2"
  )

  expect_error(
    build_nimble_bundle(
      y = y,
      backend = "sb",
      kernel = "cauchy",
      GPD = TRUE,
      components = 4
    ),
    "Cauchy kernels are never paired with GPD tails"
  )
})

